        for b in a["balances"]:
            t=float(b["free"])+float(b["locked"])
            if t>0.0001:print(f"  {b['asset']:<8}{t:>14.6f}")
    elif"error"in a:print(f"  {a['error']}")
    print("\n\U0001f4c8 Futures:")
    pos=_req(BASE_F,"/fapi/v2/positionRisk",secret=api_secret,key=api_key)
